"use client"

import { useState } from "react"

export default function VerifyAndSetup() {
    const [step, setStep] = useState<"otp" | "profile">("otp")
    const [otp, setOtp] = useState("")

    const [form, setForm] = useState({
        province: "",
        school: "",
        grade: "",
        dob: ""
    })

    const handleVerify = () => {
        if (otp.length < 6) return

        // TODO: verify OTP API

        // 👉 chuyển step
        setStep("profile")
    }

    const handleChange = (e: any) => {
        setForm({ ...form, [e.target.name]: e.target.value })
    }

    const handleSubmit = () => {
        // TODO: call API save profile

        console.log(form)
    }

    return (
        <div className="w-full h-screen bg-black flex items-center justify-center">
            <div className="w-[90%] max-w-md border border-white/10 rounded-2xl bg-white/[0.02] backdrop-blur-md p-6">

                {/* STEP 1: OTP */}
                {step === "otp" && (
                    <>
                        <h1 className="text-white text-xl font-semibold text-center">
                            Nhập mã xác nhận
                        </h1>

                        <p className="text-zinc-400 text-sm text-center mt-2">
                            Vui lòng nhập mã OTP đã gửi tới bạn
                        </p>

                        <input
                            value={otp}
                            onChange={(e) => setOtp(e.target.value)}
                            maxLength={6}
                            placeholder="••••••"
                            className="mt-6 w-full text-center tracking-[10px] text-white text-lg bg-transparent border border-zinc-700 rounded-xl py-3 outline-none focus:border-blue-500"
                        />

                        <button
                            onClick={handleVerify}
                            className="mt-5 w-full rounded-xl bg-blue-500 text-white py-3 hover:bg-blue-600 transition"
                        >
                            Xác nhận
                        </button>

                        <p className="text-center text-xs text-zinc-500 mt-4">
                            Không nhận được mã?{" "}
                            <span className="text-blue-400 cursor-pointer">
                                Gửi lại
                            </span>
                        </p>
                    </>
                )}

                {/* STEP 2: PROFILE */}
                {step === "profile" && (
                    <>
                        <h1 className="text-white text-xl font-semibold text-center">
                            Hoàn thiện hồ sơ
                        </h1>

                        <p className="text-zinc-400 text-sm text-center mt-2">
                            Chỉ mất 30 giây thôi 🚀
                        </p>

                        <div className="mt-6 space-y-4">

                            <input
                                name="province"
                                placeholder="Tỉnh / Thành phố"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-transparent border border-zinc-700 text-white outline-none focus:border-blue-500"
                            />

                            <input
                                name="school"
                                placeholder="Trường học"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-transparent border border-zinc-700 text-white outline-none focus:border-blue-500"
                            />

                            <input
                                name="grade"
                                placeholder="Lớp (VD: 10A1)"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-transparent border border-zinc-700 text-white outline-none focus:border-blue-500"
                            />

                            <input
                                type="date"
                                name="dob"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-transparent border border-zinc-700 text-white outline-none focus:border-blue-500"
                            />
                        </div>

                        <button
                            onClick={handleSubmit}
                            className="mt-6 w-full rounded-xl bg-blue-500 text-white py-3 hover:bg-blue-600 transition"
                        >
                            Hoàn tất
                        </button>
                    </>
                )}
            </div>
        </div>
    )
}